slides.mermaid:
flowchart TD
  A[Written sign] --> B[Formal SignWriting]
  B --> C[Durable text]
  B --> D[Visible written form]
  B --> E[Processable structure]
  C --> F[Storage]
  C --> G[Interchange]
  D --> H[Readable sign text]
  E --> I[Validation]
  E --> J[Search]
  E --> K[Rendering]

  classDef core fill:#f5f3ff,color:black,stroke:#7c3aed,stroke-width:3px;
  classDef node fill:#eff6ff,color:black,stroke:#2563eb,stroke-width:2px;
  classDef out fill:#f0fdf4,color:black,stroke:#16a34a,stroke-width:2px;
  class A,B core;
  class C,D,E node;
  class F,G,H,I,J,K out;

flowchart LR
  subgraph L[Incomplete reductions]
    A[Sequence only] --> B[Sorting and comparison]
    A --> C[Written form lost]
    D[Space only] --> E[Visible composition]
    D --> F[Processing lost]
  end
  subgraph R[Formal SignWriting]
    G[Temporal prefix] --> I[Sequence preserved]
    H[Spatial signbox] --> J[Composition preserved]
    I --> K[Processable writing]
    J --> K
  end

  classDef risk fill:#fef2f2,color:black,stroke:#dc2626,stroke-width:2px;
  classDef core fill:#f5f3ff,color:black,stroke:#7c3aed,stroke-width:3px;
  classDef out fill:#f0fdf4,color:black,stroke:#16a34a,stroke-width:2px;
  class A,D,C,F risk;
  class G,H core;
  class B,E,I,J,K out;

flowchart TD
  A[Two-part word] --> B[Encodings]
  A --> C[Geometry]
  B --> D[FSW and SWU]
  C --> E[Shape of a sign]
  D --> F[Grammar]
  E --> F
  F --> G[Searching signed text]
  F --> H[Rendering]
  H --> I[Styling]
  G --> J[Practice]
  H --> J
  I --> J

  classDef core fill:#f5f3ff,color:black,stroke:#7c3aed,stroke-width:3px;
  classDef node fill:#eff6ff,color:black,stroke:#2563eb,stroke-width:2px;
  classDef out fill:#f0fdf4,color:black,stroke:#16a34a,stroke-width:2px;
  class A,F core;
  class B,C,D,E,G,H,I node;
  class J out;
